class Solution:
    def solve(self, q: list[int]) -> bool:
        if not q:
            return True
        if len(q) == 1:
            q.pop(0)
        front = q[0]
        q.pop(0)
        if front == q[0]:
            return False
        q.append(front)
        return True

    def remove(self, q: list[int], index: int) -> list[int]:
        return q[:index] + q[index+1:]

    def add(self, q: list[int], element: int) -> list[int]:
        return q + [element]

def main():
    n = int(input())
    q = list(map(int, input().split()))
    s = Solution()
    print(s.solve(q))

if __name__ == '__main__':
    main()

