#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;
class Solution {
public:
    bool solve(vector<int>& q) {
        if (q.empty()) return true; if (q.size() == 1) { q.pop_back(); return q.empty(); }
        int front = q.front(); q.pop_front(); if (front == q.front()) return false; q.push_back(front);
        return true;
    }
};

int main() {
    int n;
    cin >> n;
    vector<int> q(n);
    for (int& i : q) cin >> i;
    Solution s;
    cout << (s.solve(q) ? "true" : "false") << endl;
    return 0;
}
